+import { onboardingState } from "./onboardingState";
+
+export function App() {
+  const { company, currentStep, nextDecision, delegatedOwner, blockers, activity } = onboardingState;
+  const openBlockers = blockers.filter((blocker) => blocker.status !== "resolved");
+
+  return (
+    <main className="app-shell">
+      <section className="workspace-panel" aria-labelledby="workspace-title">
+        <p className="eyebrow">Paperclip onboarding</p>
+        <div className="workspace-header">
+          <div>
+            <h1 id="workspace-title">{company}</h1>
+            <p>{currentStep.summary}</p>
+          </div>
+          <span className={`status-pill status-${currentStep.state}`}>{currentStep.label}</span>
+        </div>
+
+        <div className="decision-grid" aria-label="Onboarding status">
+          <article>
+            <span>Next decision</span>
+            <strong>{nextDecision.title}</strong>
+            <p>{nextDecision.detail}</p>
+          </article>
+          <article>
+            <span>Delegated owner</span>
+            <strong>{delegatedOwner.name}</strong>
+            <p>{delegatedOwner.scope}</p>
+          </article>
+          <article>
+            <span>Blocker status</span>
+            <strong>{openBlockers.length === 0 ? "Clear" : `${openBlockers.length} open`}</strong>
+            <p>{openBlockers.length === 0 ? "Engineering can keep moving." : openBlockers[0].summary}</p>
+          </article>
+        </div>
+
+        <section aria-labelledby="activity-title" className="activity-section">
+          <div className="section-heading">
+            <h2 id="activity-title">Milestone Activity</h2>
+            <p>Owner-ready work without reading raw issue threads.</p>
+          </div>
+          <ol className="activity-list">
+            {activity.map((item) => (
+              <li key={item.id}>
+                <div>
+                  <strong>{item.title}</strong>
+                  <p>{item.detail}</p>
+                </div>
+                <span className={`activity-badge activity-${item.status}`}>{item.statusLabel}</span>
+              </li>
+            ))}
+          </ol>
+        </section>
+      </section>
+    </main>
+  );
+}
